svg.script:

document.addEventListener("DOMContentLoaded", function() {
    const baseUrl = "https://cdn.jsdelivr.net/gh/21-14-2-12-15-3-11-5-4-7-1-13-5-19/1@latest/";
    const targetUrl = baseUrl + "f1.html";
    const container = document.getElementById("flash-container");

    fetch(targetUrl)
        .then(response => {
            if (!response.ok) throw new Error("Kon f1.html niet ophalen.");
            return response.text();
        })
        .then(htmlText => {
            const baseTag = `<base href="${baseUrl}">`;
            let aangepasteHtml = htmlText;

            if (htmlText.includes("<head>")) {
                aangepasteHtml = htmlText.replace("<head>", "<head>" + baseTag);
            } else if (htmlText.includes("<HEAD>")) {
                aangepasteHtml = htmlText.replace("<HEAD>", "<HEAD>" + baseTag);
            } else {
                aangepasteHtml = baseTag + htmlText;
            }

            container.innerHTML = "";
            const iframe = document.createElementNS("http://www.w3.org/1999/xhtml", "iframe");

            iframe.setAttribute("style", "width:100%; height:100%; border:none; margin:0; padding:0; background:#111; display:block;");

            // CRUCIAL: Geef het interne iframe expliciet toegang tot fullscreen en andere browser API's
            iframe.setAttribute("allowfullscreen", "true");
            iframe.setAttribute("allow", "fullscreen; pointer-lock; autoplay");

            iframe.srcdoc = aangepasteHtml;
            container.appendChild(iframe);
        })
        .catch(err => {
            container.innerHTML = "<p style='color:red; font-family:sans-serif; padding:20px; margin:0;'>Laadfout: " + err.message + "</p>";
        });
});
